# Retrieval observability: RAGAS offline evaluation
# pip install ragas datasets langchain
from ragas import evaluate
from ragas.metrics import (
    context_precision, context_recall,
    faithfulness, answer_relevancy,
)
from datasets import Dataset

def evaluate_retrieval_quality(rag_chain, eval_dataset: list[dict]) -> dict:
    """
    eval_dataset: list of {"question": str, "ground_truth": str, "contexts": [str]}
    Each entry is a golden QA pair with pre-fetched retrieved contexts.
    """
    rows = {"question": [], "answer": [], "contexts": [], "ground_truth": []}
    for item in eval_dataset:
        answer = rag_chain.invoke(item["question"])
        rows["question"].append(item["question"])
        rows["answer"].append(answer)
        rows["contexts"].append(item["contexts"])
        rows["ground_truth"].append(item["ground_truth"])
    ds = Dataset.from_dict(rows)
    result = evaluate(
        ds, metrics=[
            context_precision, context_recall,
            faithfulness, answer_relevancy,
        ]
    )
    return result.to_pandas().to_dict(orient="records")
